import{_ as i,o as t,c as o,ai as a}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"Menu Bar","description":"","frontmatter":{"summary":"Menu bar status logic and what is surfaced to users","read_when":["Tweaking mac menu UI or status logic"],"title":"Menu Bar"},"headers":[],"relativePath":"platforms/mac/menu-bar.md","filePath":"platforms/mac/menu-bar.md","lastUpdated":null}'),l={name:"platforms/mac/menu-bar.md"};function s(n,e,d,c,r,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="menu-bar-status-logic" tabindex="-1"><a class="header-anchor" href="#menu-bar-status-logic">#</a> Menu Bar Status Logic</h1><h2 id="what-is-shown" tabindex="-1"><a class="header-anchor" href="#what-is-shown">#</a> What is shown</h2><ul><li>We surface the current agent work state in the menu bar icon and in the first status row of the menu.</li><li>Health status is hidden while work is active; it returns when all sessions are idle.</li><li>The “Nodes” block in the menu lists <strong>devices</strong> only (paired nodes via <code>node.list</code>), not client/presence entries.</li><li>A “Usage” section appears under Context when provider usage snapshots are available.</li></ul><h2 id="state-model" tabindex="-1"><a class="header-anchor" href="#state-model">#</a> State model</h2><ul><li>Sessions: events arrive with <code>runId</code> (per-run) plus <code>sessionKey</code> in the payload. The “main” session is the key <code>main</code>; if absent, we fall back to the most recently updated session.</li><li>Priority: main always wins. If main is active, its state is shown immediately. If main is idle, the most recently active non‑main session is shown. We do not flip‑flop mid‑activity; we only switch when the current session goes idle or main becomes active.</li><li>Activity kinds: <ul><li><code>job</code>: high‑level command execution (<code>state: started|streaming|done|error</code>).</li><li><code>tool</code>: <code>phase: start|result</code> with <code>toolName</code> and <code>meta/args</code>.</li></ul></li></ul><h2 id="iconstate-enum-swift" tabindex="-1"><a class="header-anchor" href="#iconstate-enum-swift">#</a> IconState enum (Swift)</h2><ul><li><code>idle</code></li><li><code>workingMain(ActivityKind)</code></li><li><code>workingOther(ActivityKind)</code></li><li><code>overridden(ActivityKind)</code> (debug override)</li></ul><h3 id="activitykind-→-glyph" tabindex="-1"><a class="header-anchor" href="#activitykind-→-glyph">#</a> ActivityKind → glyph</h3><ul><li><code>exec</code> → 💻</li><li><code>read</code> → 📄</li><li><code>write</code> → ✍️</li><li><code>edit</code> → 📝</li><li><code>attach</code> → 📎</li><li>default → 🛠️</li></ul><h3 id="visual-mapping" tabindex="-1"><a class="header-anchor" href="#visual-mapping">#</a> Visual mapping</h3><ul><li><code>idle</code>: normal critter.</li><li><code>workingMain</code>: badge with glyph, full tint, leg “working” animation.</li><li><code>workingOther</code>: badge with glyph, muted tint, no scurry.</li><li><code>overridden</code>: uses the chosen glyph/tint regardless of activity.</li></ul><h2 id="status-row-text-menu" tabindex="-1"><a class="header-anchor" href="#status-row-text-menu">#</a> Status row text (menu)</h2><ul><li>While work is active: <code>&lt;Session role&gt; · &lt;activity label&gt;</code><ul><li>Examples: <code>Main · exec: pnpm test</code>, <code>Other · read: apps/macos/Sources/OpenSoul/AppState.swift</code>.</li></ul></li><li>When idle: falls back to the health summary.</li></ul><h2 id="event-ingestion" tabindex="-1"><a class="header-anchor" href="#event-ingestion">#</a> Event ingestion</h2><ul><li>Source: control‑channel <code>agent</code> events (<code>ControlChannel.handleAgentEvent</code>).</li><li>Parsed fields: <ul><li><code>stream: &quot;job&quot;</code> with <code>data.state</code> for start/stop.</li><li><code>stream: &quot;tool&quot;</code> with <code>data.phase</code>, <code>name</code>, optional <code>meta</code>/<code>args</code>.</li></ul></li><li>Labels: <ul><li><code>exec</code>: first line of <code>args.command</code>.</li><li><code>read</code>/<code>write</code>: shortened path.</li><li><code>edit</code>: path plus inferred change kind from <code>meta</code>/diff counts.</li><li>fallback: tool name.</li></ul></li></ul><h2 id="debug-override" tabindex="-1"><a class="header-anchor" href="#debug-override">#</a> Debug override</h2><ul><li>Settings ▸ Debug ▸ “Icon override” picker: <ul><li><code>System (auto)</code> (default)</li><li><code>Working: main</code> (per tool kind)</li><li><code>Working: other</code> (per tool kind)</li><li><code>Idle</code></li></ul></li><li>Stored via <code>@AppStorage(&quot;iconOverride&quot;)</code>; mapped to <code>IconState.overridden</code>.</li></ul><h2 id="testing-checklist" tabindex="-1"><a class="header-anchor" href="#testing-checklist">#</a> Testing checklist</h2><ul><li>Trigger main session job: verify icon switches immediately and status row shows main label.</li><li>Trigger non‑main session job while main idle: icon/status shows non‑main; stays stable until it finishes.</li><li>Start main while other active: icon flips to main instantly.</li><li>Rapid tool bursts: ensure badge does not flicker (TTL grace on tool results).</li><li>Health row reappears once all sessions idle.</li></ul>',19)])])}const p=i(l,[["render",s]]);export{m as __pageData,p as default};
